function registerCodeHash(address target) external {
  // Ensure that the target contract has not already had a hash registered.
  require(_cachedHashes[target] == bytes32(0), "Target already registered.");

  // Ensure that the target contract currently has runtime code.
  uint256 currentCodeSize;
  assembly { currentCodeSize := extcodesize(target) }
  require(currentCodeSize > 0, "Target currently has no runtime code.");

  // Retrieve the current runtime code hash of the target contract.
  bytes32 currentCodeHash;
  assembly { currentCodeHash := extcodehash(target) }

  // Register the runtime code hash for the target contract.
  _cachedHashes[target] = currentCodeHash;
}

function initiateUpgrade(
  address controller,
  address beacon,
  address implementation,
  uint256 extraTime
) external onlyOwner {
  require(controller != address(0), "Must specify a controller address.");

  require(beacon != address(0), "Must specify a beacon address.");

  // Ensure that the implementaton contract is not the null address.
  require(
    implementation != address(0),
    "Implementation cannot be the null address."
  );

  // Ensure that the implementation contract has code via extcodesize.
  uint256 size;
  assembly {
    size := extcodesize(implementation)
  }
  require(size > 0, "Implementation must have contract code.");

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.upgrade.selector,
    abi.encode(controller, beacon, implementation),
    extraTime
  );
}

function _permitTransferFrom(
    PermitTransferFrom memory permit,
    SignatureTransferDetails calldata transferDetails,
    address owner,
    bytes32 dataHash,
    bytes calldata signature
) private {
    uint256 requestedAmount = transferDetails.requestedAmount;

    if (block.timestamp > permit.deadline) revert SignatureExpired(permit.deadline);
    if (requestedAmount > permit.permitted.amount) revert InvalidAmount(permit.permitted.amount);

    _useUnorderedNonce(owner, permit.nonce);

    signature.verify(_hashTypedData(dataHash), owner);

    ERC20(permit.permitted.token).safeTransferFrom(owner, transferDetails.to, requestedAmount);
}

function _executeOptimizedBatch(
    bytes32 mode,
    bytes calldata executionData,
    address to,
    bytes[] calldata dataArr,
    bytes calldata opData
) internal virtual {
    // Silence compiler warning on unused variables.
    mode = mode;
    executionData = executionData;
    // Very basic auth to only allow this contract to be called by itself.
    // Override this function to perform more complex auth with `opData`.
    if (opData.length == uint256(0)) {
        require(msg.sender == address(this));
        // Remember to return `_executeOptimizedBatch(to, dataArr, extraData)`
        // when you override this function.
        return _executeOptimizedBatch(to, dataArr, bytes32(0));
    }
    revert(); // In your override, replace this with logic to operate on `opData`.
}
